import './App.css';
import './components/searchbar'
import SearchBar from './components/searchbar';
import './index.css'
import ContactCard from './components/ContactCard'
import { FaPencilAlt } from "react-icons/fa";
import { useState } from "react";
function App() {


  const contacts = [
  {
    id: 1,
    name: "Ali Khan",
    phone: "03001234567",
    email: "ali.khan@email.com"
  },
  {
    id: 2,
    name: "Sara Ahmed",
    phone: "03111234567",
    email: "sara.ahmed@email.com"
  },
  {
    id: 3,
    name: "Ahmed Raza",
    phone: "03221234567",
    email: "ahmed.raza@email.com"
  },
  {
    id: 4,
    name: "Fatima Noor",
    phone: "03331234567",
    email: "fatima.noor@email.com"
  }
];
const [contact,setContact]=useState(contacts)
const [selectedContact,setSelectedContact]=useState(null)


  return(
    <>

  <div className='app-container'>
    <h1>Contact List</h1>
    <p>Manage your contacts easily</p>
    <div>
    <SearchBar className="search-add-container"/>

    <button className="add-contact-btn">+ Add contacts </button>
    </div>
    <div style={{ padding: "20px" }}>
      {contacts.map((contact) => (
        <div key={contact.id} style={{ position: "relative", marginBottom: "12px" }}>

          <FaPencilAlt
            style={{ position: "absolute", top: "8px", right: "8px", cursor: "pointer" }}
            onClick={() => setSelectedContact(contact)} // when clicked, store selected contact
          />


          <div
            style={{
              padding: "12px 16px",
              border: "1px solid #e0e0e0",
              borderRadius: "8px",
              backgroundColor: "#f9f9f9",
            }}
          >
            <p style={{ margin: "0", fontWeight: "600" }}>{contact.name}</p>
          </div>
        </div>
      ))}

      {selectedContact && (
      <ContactCard
  name={selectedContact.name}
  email={selectedContact.email}
  phone={selectedContact.phone}
  onUpdate={() => alert("Update " + selectedContact.name)}
  onDelete={() => {
    setContact(contacts.filter(c => c.id !== selectedContact.id));
    setSelectedContact(null); // close the card after deletion
  }}
/>
      )}  
    </div>


    <button>+</button>

    <p>Get started by adding your first contact</p>
    <button className="first-contact-btn">Add your first contact</button>

  </div>




    </>
  )
}

export default App;
